settings.default:
.custom-container {
  padding: 30px;
  background: linear-gradient(135deg, rgba(255,255,255,0.02) 0%, rgba(255,255,255,0.05) 100%);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 12px;
  text-align: center;
  backdrop-filter: blur(10px);
}
.custom-container h3 {
  margin: 0 0 10px;
  color: #fff;
  font-size: 1.4rem;
}
.custom-container p {
  color: #8e9099;
  font-size: 0.95rem;
  margin-bottom: 20px;
}
.custom-btn {
  background: #ffffff;
  color: #000000;
  border: none;
  padding: 8px 16px;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 600;
  transition: opacity 0.2s;
}
.custom-btn:hover {
  opacity: 0.9;
}

// 'this' refers to the custom element, so you can scope selectors inside the Shadow DOM:
const btn = this.shadowRoot.querySelector('.custom-btn');
if (btn) {
  btn.addEventListener('click', () => {
    alert('Hello from Custom HTML Block!');
  });
}
